func (*App) prepareListenData(addr string, isTLS bool, cfg ListenConfig) ListenData {
	host, port := parseAddr(addr)
	if host == "" {
		if cfg.ListenerNetwork == NetworkTCP6 {
			host = "[::1]"
		} else {
			host = globalIpv4Addr
		}
	}

	return ListenData{
		Host:	host,
		Port:	port,
		TLS:	isTLS,
	}
}
